package com.example.socialloginbeta

import android.content.Intent
import android.os.Bundle
import android.util.Log
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import com.facebook.*
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.SignInButton
import com.google.android.gms.common.api.ApiException
import com.google.android.gms.tasks.Task

class LoginActivity : AppCompatActivity() {

    private val FACEBOOK_APP_ID = "123456789012345"
    private val FACEBOOK_APP_SECRET = "abcdef1234567890abcdef1234567890"

    private val GOOGLE_CLIENT_ID = "1234-abcdef.apps.googleusercontent.com"
    private val GOOGLE_CLIENT_SECRET = "GOCSpx-AbCdEf123456"

    private lateinit var callbackManager: CallbackManager
    private lateinit var googleSignInClient: GoogleSignInClient
    private lateinit var statusTextView: TextView

    private val RC_SIGN_IN = 9001

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        statusTextView = findViewById(R.id.statusTextView)

        // Initialize Facebook Login
        FacebookSdk.setApplicationId(FACEBOOK_APP_ID)
        FacebookSdk.setClientToken(FACEBOOK_APP_SECRET)
        FacebookSdk.sdkInitialize(applicationContext)

        callbackManager = CallbackManager.Factory.create()

        val facebookLoginButton: com.facebook.login.widget.LoginButton = findViewById(R.id.facebookLoginButton)
        facebookLoginButton.setPermissions(listOf("email", "public_profile"))
        facebookLoginButton.registerCallback(callbackManager, object : FacebookCallback<LoginResult> {
            override fun onSuccess(result: LoginResult) {
                Log.d("FacebookLogin", "onSuccess: ${result.accessToken.token}")
                val profile = Profile.getCurrentProfile()
                val name = profile?.name ?: "Unknown User"
                statusTextView.text = getString(R.string.facebook_login_success, name)
                Toast.makeText(this@LoginActivity, "Logged in as $name", Toast.LENGTH_SHORT).show()
                val request = GraphRequest.newMeRequest(
                    result.accessToken
                ) { jsonObject, response ->
                    Log.d("FacebookLogin", "Graph Request Response: $jsonObject")
                }
                val parameters = Bundle()
                parameters.putString("fields", "id,name,email,picture.type(large)")
                request.parameters = parameters
                request.executeAsync()
            }

            override fun onCancel() {
                Log.d("FacebookLogin", "onCancel")
                statusTextView.text = getString(R.string.facebook_login_canceled)
                Toast.makeText(this@LoginActivity, R.string.facebook_login_canceled, Toast.LENGTH_SHORT).show()
            }

            override fun onError(error: FacebookException) {
                Log.e("FacebookLogin", "onError: ${error.message}", error)
                statusTextView.text = getString(R.string.error_login_failed)
                Toast.makeText(this@LoginActivity, getString(R.string.error_login_failed) + ": " + error.message, Toast.LENGTH_LONG).show()
            }
        })

        // Initialize Google Sign-In
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestIdToken(GOOGLE_CLIENT_ID)
            .requestEmail()
            .build()

        googleSignInClient = GoogleSignIn.getClient(this, gso)

        val googleSignInButton: SignInButton = findViewById(R.id.googleSignInButton)
        googleSignInButton.setSize(SignInButton.SIZE_STANDARD)
        googleSignInButton.setOnClickListener {
            signInWithGoogle()
        }

        checkExistingLogins()
    }

    private fun checkExistingLogins() {
        val accessToken = AccessToken.getCurrentAccessToken()
        val isLoggedInFacebook = accessToken != null && !accessToken.isExpired
        if (isLoggedInFacebook) {
            val profile = Profile.getCurrentProfile()
            val name = profile?.name ?: "Unknown User"
            statusTextView.text = getString(R.string.facebook_login_success, name)
            Toast.makeText(this, "Already logged in to Facebook as $name", Toast.LENGTH_SHORT).show()
        }

        val account = GoogleSignIn.getLastSignedInAccount(this)
        if (account != null) {
            val name = account.displayName ?: "Unknown User"
            statusTextView.text = getString(R.string.google_login_success, name)
            Toast.makeText(this, "Already logged in to Google as $name", Toast.LENGTH_SHORT).show()
        }
    }

    private fun signInWithGoogle() {
        val signInIntent = googleSignInClient.signInIntent
        startActivityForResult(signInIntent, RC_SIGN_IN)
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        callbackManager.onActivityResult(requestCode, resultCode, data)
        super.onActivityResult(requestCode, resultCode, data)

        if (requestCode == RC_SIGN_IN) {
            val task = GoogleSignIn.getSignedInAccountFromIntent(data)
            handleGoogleSignInResult(task)
        }
    }

    private fun handleGoogleSignInResult(completedTask: Task<GoogleSignInAccount>) {
        try {
            val account = completedTask.getResult(ApiException::class.java)
            Log.d("GoogleSignIn", "Google Sign-In success: ID=${account.id}, Email=${account.email}, DisplayName=${account.displayName}")
            Log.d("GoogleSignIn", "ID Token: ${account.idToken}")
            statusTextView.text = getString(R.string.google_login_success, account.displayName ?: "Unknown User")
            Toast.makeText(this, "Logged in as ${account.displayName}", Toast.LENGTH_SHORT).show()
        } catch (e: ApiException) {
            Log.w("GoogleSignIn", "signInResult:failed code=" + e.statusCode, e)
            statusTextView.text = getString(R.string.google_sign_in_failed)
            Toast.makeText(this, getString(R.string.google_sign_in_failed), Toast.LENGTH_LONG).show()
        }
    }

    private fun logoutFacebook() {
        LoginManager.getInstance().logOut()
        statusTextView.text = "Logged out from Facebook."
        Toast.makeText(this, "Logged out from Facebook", Toast.LENGTH_SHORT).show()
    }

    private fun logoutGoogle() {
        googleSignInClient.signOut().addOnCompleteListener(this) { task ->
            if (task.isSuccessful) {
                statusTextView.text = "Logged out from Google."
                Toast.makeText(this, "Logged out from Google", Toast.LENGTH_SHORT).show()
            } else {
                Toast.makeText(this, "Failed to log out from Google", Toast.LENGTH_SHORT).show()
            }
        }
    }
}